exercises.solution_code:
#include <algorithm>
#include <iostream>
#include <numeric>
#include <vector>

int main()
{
    int n{};
    std::cin >> n;

    std::vector<int> v(n);
    for (int i{ 0 }; i < n; ++i)
        std::cin >> v[i];

    int target{};
    std::cin >> target;

    std::sort(v.begin(), v.end());

    std::cout << "Sorted:";
    for (int val : v)
        std::cout << ' ' << val;
    std::cout << '\n';

    std::cout << "Min: " << *std::min_element(v.begin(), v.end()) << '\n';

    std::cout << "Sum: " << std::accumulate(v.begin(), v.end(), 0) << '\n';

    auto it{ std::find(v.begin(), v.end(), target) };
    std::cout << "Found " << target << ": ";
    if (it != v.end())
        std::cout << "yes\n";
    else
        std::cout << "no\n";

    return 0;
}

