exercises.solution_code:
#include <algorithm>
#include <iostream>
#include <numeric>
#include <vector>

void doubleValue(int& x)
{
    x *= 2;
}

int main()
{
    int n{};
    int q{};
    std::cin >> n >> q;

    std::vector<int> v(n);
    for (int i{ 0 }; i < n; ++i)
        std::cin >> v[i];

    std::cout << "Max: " << *std::max_element(v.begin(), v.end()) << '\n';

    std::cout << "Count of " << q << ": " << std::count(v.begin(), v.end(), q) << '\n';

    std::for_each(v.begin(), v.end(), doubleValue);

    std::cout << "Double sum: " << std::accumulate(v.begin(), v.end(), 0) << '\n';

    return 0;
}
